import{_ as i,o as s,c as n,a3 as a}from"./chunks/framework.CqLY61E_.js";const h=JSON.parse('{"title":"03 — Index de colonne","description":"","frontmatter":{"title":"03 — Index de colonne","aside":true},"headers":[],"relativePath":"modules/05-ddl-avance/03-index-de-colonne.md","filePath":"modules/05-ddl-avance/03-index-de-colonne.md"}'),t={name:"modules/05-ddl-avance/03-index-de-colonne.md"};function l(r,e,d,o,u,p){return s(),n("div",null,[...e[0]||(e[0]=[a(`<h1 id="_03-—-index-de-colonne" tabindex="-1">03 — Index de colonne <a class="header-anchor" href="#_03-—-index-de-colonne" aria-label="Permalink to &quot;03 — Index de colonne&quot;">​</a></h1><h2 id="objectif" tabindex="-1">Objectif <a class="header-anchor" href="#objectif" aria-label="Permalink to &quot;Objectif&quot;">​</a></h2><p>Comprendre à quoi sert un index, quand en créer un, et pourquoi un index peut accélérer certaines requêtes tout en ajoutant un coût sur les écritures.</p><hr><h2 id="l-essentiel-a-connaitre" tabindex="-1">L&#39;essentiel à connaître <a class="header-anchor" href="#l-essentiel-a-connaitre" aria-label="Permalink to &quot;L&#39;essentiel à connaître&quot;">​</a></h2><p>Un index est une structure supplémentaire qu&#39;une base de données maintient pour retrouver plus vite certaines lignes.</p><p>Sans index, le SGBD doit souvent lire beaucoup de lignes pour répondre à une requête.</p><p>Avec un index, il peut parfois accéder plus rapidement aux lignes utiles.</p><p>Exemple d&#39;idée :</p><ul><li>chercher un client par <code>courriel</code></li><li>filtrer des pistes par <code>genre_id</code></li><li>joindre <code>facture</code> à <code>client</code> via <code>client_id</code></li></ul><hr><h2 id="pourquoi-un-index-peut-aider" tabindex="-1">Pourquoi un index peut aider <a class="header-anchor" href="#pourquoi-un-index-peut-aider" aria-label="Permalink to &quot;Pourquoi un index peut aider&quot;">​</a></h2><p>Un index est surtout utile quand une colonne est souvent utilisée dans :</p><ul><li>un <code>where</code></li><li>un <code>join</code></li><li>un <code>order by</code></li></ul><p>Exemple :</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> client</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> courriel </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;test@example.com&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>Si cette recherche est fréquente, un index sur <code>courriel</code> peut aider.</p><hr><h2 id="creer-un-index" tabindex="-1">Créer un index <a class="header-anchor" href="#creer-un-index" aria-label="Permalink to &quot;Créer un index&quot;">​</a></h2><p>Syntaxe :</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">create</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> index</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> nom_index</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">on</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> nom_table (nom_colonne);</span></span></code></pre></div><p>Exemple avec Chinook :</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">create</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> index</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> idx_client_courriel</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">on</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> client (courriel);</span></span></code></pre></div><p>Exemple sur une colonne de relation :</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">create</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> index</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> idx_facture_client_id</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">on</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> facture (client_id);</span></span></code></pre></div><hr><h2 id="ce-qu-un-index-ne-fait-pas" tabindex="-1">Ce qu&#39;un index ne fait pas <a class="header-anchor" href="#ce-qu-un-index-ne-fait-pas" aria-label="Permalink to &quot;Ce qu&#39;un index ne fait pas&quot;">​</a></h2><p>Un index n&#39;améliore pas tout automatiquement.</p><p>Il peut être peu utile si :</p><ul><li>la table est très petite</li><li>presque toutes les lignes doivent être lues de toute façon</li><li>la colonne a très peu de valeurs différentes</li></ul><hr><h2 id="cout-d-un-index" tabindex="-1">Coût d&#39;un index <a class="header-anchor" href="#cout-d-un-index" aria-label="Permalink to &quot;Coût d&#39;un index&quot;">​</a></h2><p>Créer un index apporte aussi un coût :</p><ul><li>l&#39;index prend de l&#39;espace disque</li><li>Surtout, PostgreSQL doit aussi le mettre à jour lors des <code>insert</code>, <code>update</code> et <code>delete</code></li></ul><p>Donc :</p><ul><li>plus d&#39;index peut améliorer certaines lectures</li><li>mais trop d&#39;index peut ralentir les écritures</li></ul><hr><h2 id="index-et-cles" tabindex="-1">Index et clés <a class="header-anchor" href="#index-et-cles" aria-label="Permalink to &quot;Index et clés&quot;">​</a></h2><p>Quelques repères utiles :</p><ul><li>une clé primaire crée généralement un index</li><li>une contrainte <code>unique</code> crée généralement un index unique</li><li>les colonnes de clé étrangère sont souvent de bonnes candidates à l&#39;indexation</li></ul><p>Dans Chinook, plusieurs index existent déjà sur des colonnes servant aux relations.</p><hr><h2 id="supprimer-un-index" tabindex="-1">Supprimer un index <a class="header-anchor" href="#supprimer-un-index" aria-label="Permalink to &quot;Supprimer un index&quot;">​</a></h2><p>Syntaxe :</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">drop</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> index</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> nom_index;</span></span></code></pre></div><p>Exemple :</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">drop</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> index</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> idx_client_courriel;</span></span></code></pre></div><p>Comme pour d&#39;autres opérations de maintenance :</p><ul><li>on supprime rarement un index sans raison</li><li>il faut vérifier l&#39;impact sur les requêtes avant de le retirer</li></ul><hr><h2 id="a-retenir" tabindex="-1">À retenir <a class="header-anchor" href="#a-retenir" aria-label="Permalink to &quot;À retenir&quot;">​</a></h2><ul><li>un index sert surtout à accélérer certaines lectures</li><li>il est particulièrement utile sur des colonnes souvent filtrées, jointes ou triées</li><li>un index a aussi un coût sur l&#39;espace et les écritures</li><li>il faut l&#39;ajouter avec intention, pas automatiquement partout</li></ul><hr><h3 id="sources" tabindex="-1">Sources <a class="header-anchor" href="#sources" aria-label="Permalink to &quot;Sources&quot;">​</a></h3><ul><li><a href="https://www.postgresql.org/docs/current/indexes.html" target="_blank" rel="noreferrer">PostgreSQL Documentation — Indexes</a></li><li><a href="https://www.postgresql.org/docs/current/sql-createindex.html" target="_blank" rel="noreferrer">PostgreSQL Documentation — CREATE INDEX</a></li></ul><hr><div class="my-6 rounded-lg border border-blue-300 bg-blue-50 p-4 text-blue-900"><strong class="block">ℹ️ À faire maintenant</strong><p class="m-0"> Poursuivez dans le <a href="./../../labs/lab08-ddl-maintenance" class="font-semibold underline hover:text-blue-700"> laboratoire 8 </a> en ajoutant quelques index simples sur des colonnes souvent utilisées dans les recherches ou les relations. </p></div>`,57)])])}const k=i(t,[["render",l]]);export{h as __pageData,k as default};
